#include <bits/stdc++.h>
#define ll long double
using namespace std;

const int N=1e5+10;

struct Node{
    int l,r,x;
};

int T,n,l,p,s[N],lst[N],path[N],cnt;
char st[N][35];
ll f[N];
deque<Node> q;

inline ll W(int x,int y){
    ll ans=1,base=abs(s[y]-s[x]-1-l);
    for(int i=1;i<=p;i++)
        ans*=base;
    return ans;
}

int main(){
    scanf("%d",&T);
    while(T--){
        scanf("%d%d%d",&n,&l,&p);
        for(int i=1;i<=n;i++){
            scanf("%s",st[i]);
            s[i]=s[i-1]+strlen(st[i])+1;
        }
        while(q.size())
            q.pop_back();
        q.push_back({1,n,0});
        for(int i=1;i<=n;i++){
            f[i]=f[q.front().x]+W(q.front().x,i);
            lst[i]=q.front().x;
            q.front().l++;
            if(q.front().l>q.front().r)
                q.pop_front();
            if(i==n)
                break;
            int lp=n+1;
            while(q.size()){
                if(f[q.back().x]+W(q.back().x,q.back().l)>=f[i]+W(i,q.back().l))
                    lp=q.back().l,q.pop_back();
                else if(f[q.back().x]+W(q.back().x,q.back().r)<f[i]+W(i,q.back().r))
                    break;
                else{
                    int le=q.back().l,ri=q.back().r;
                    while(le<ri){
                        int mid=le+ri>>1;
                        if(f[q.back().x]+W(q.back().x,mid)>=f[i]+W(i,mid))
                            ri=mid;
                        else
                            le=mid+1;
                    }
                    q.back().r=le-1;
                    lp=le;
                    break;
                }
            }
            if(lp<=n)
                q.push_back({lp,n,i});
        }
        //printf("%lld\n",f[n]);
        if(f[n]>1e18)
            puts("Too hard to arrange");
        else{
            printf("%lld\n",(long long)f[n]);
            cnt=0;
            for(int i=n;i;i=lst[i])
                path[++cnt]=i;
            reverse(path+1,path+cnt+1);
            for(int i=1;i<=cnt;i++){
                for(int j=path[i-1]+1;j<=path[i];j++){
                    printf("%s",st[j]);
                    if(j<path[i])
                        printf(" ");
                }
                puts("");
            }
        }
        printf("--------------------");
        if(T)
            puts("");
    }
    return 0;
}
